// External dependencies
const uuid = require('uuid');

let results = [];

for (const item of $input.all()) {
  // Generate one business key per file
  const business_key = uuid.v4();

  // Find binary key (e.g. 'data', 'attachment_0', etc.)
  const binaryKeys = Object.keys(item.binary || {});
  if (binaryKeys.length === 0) continue;

  const key = binaryKeys[0];
  const binaryData = item.binary[key];

  // Get base64 file content
  const base64Content = binaryData.data || null;

  // Parse extracted document content
  let data = JSON.parse(item.json.message.content);

  // Attach business_key to the document
  data.business_key = business_key;

  // Attach business_key to all transactions (if any)
  if (Array.isArray(data.transactions)) {
    data.transactions = data.transactions.map(tx => ({
      ...tx,
      business_key
    }));
  }

  // Push output
  results.push({
    json: {
      business_key,  // unique per file
      data,          // extracted + enriched JSON
      fileName: item.json.fileName || binaryData.fileName,
      mimeType: item.json.mimeType || binaryData.mimeType,
      text: item.json.text || "",     // from Extract from File
      content: base64Content          // base64 string of file
    }
  });
}

return results;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
